import io
import torch
import torchvision.transforms as transforms
from PIL import Image
from flask import Flask, request, jsonify

app = Flask(__name__)
model = torch.load('your_model.pth', map_location=torch.device('cpu'))
model.eval()

def predict_image_class(image):
    image_tensor = transforms.ToTensor()(image).unsqueeze(0)
    with torch.no_grad():
        outputs = model(image_tensor)
    _, predicted = torch.max(outputs, 1)
    confidence = torch.nn.functional.softmax(outputs, dim=1)[0][predicted[0]].item()
    return predicted.item(), confidence

@app.route('/classify-image', methods=['POST'])
def classify_image():
    if 'image' not in request.files:
        return "No image uploaded", 400
    
    image_stream = request.files['image'].read()
    image = Image.open(io.BytesIO(image_stream)).convert('RGB')
    
    predicted_class, confidence = predict_image_class(image)
    
    return jsonify({
        'predicted_class': predicted_class,
        'confidence': confidence
    })

if __name__ == '__main__':
    app.run()